def do_insert(cursor, data, otype):
    inserted = 0
    for row in data:
        try:
            cursor.execute("""
                INSERT INTO animal (type, name_cn, name_en, scientific_name, kingdom, phylum, class,
                order_name, family, genus, category, feature, is_endangered, region, description)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                ON DUPLICATE KEY UPDATE name_en=VALUES(name_en)
            """, (otype, row[0], row[1], row[2], row[3], row[4], row[5], row[6], row[7], row[8], row[9], row[10], int(row[11]), row[12], row[13]))
            inserted += 1
        except Exception as e:
            pass
    return inserted

