# Load plants from JSON
plants = json.load(open("/root/.openclaw/workspace/plants_data.json", encoding="utf-8"))
imported_plants = 0
for p in plants:
    try:
        cur.execute("""
            INSERT INTO animal (type, name_cn, name_en, scientific_name, kingdom, phylum, class,
            order_name, family, genus, species, subspecies, category, feature,
            is_endangered, region, description, flower_color, leaf_type, fruit_type, habitat)
            VALUES ("plant",%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        """, (p.get("name_cn",""), p.get("name_en",""), p.get("scientific_name",""),
              p.get("kingdom","植物界"), p.get("phylum",""), p.get("class",""),
              p.get("order_name",""), p.get("family",""), p.get("genus",""),
              p.get("species",""), p.get("subspecies",""), p.get("category",""),
              p.get("feature",""), int(p.get("is_endangered") or 0),
              p.get("region",""), p.get("description",""),
              p.get("flower_color",""), p.get("leaf_type",""),
              p.get("fruit_type",""), p.get("habitat","")))
        imported_plants += 1
    except Exception as e:
        pass
conn.commit()
cur.close(); conn.close()
print(f"Plants inserted: {imported_plants}")
